                dic[(x[0], x[1], x[2])] = [x[3], x[4]]
            else:
                dic[(x[0], x[1], x[2])][0] = list(set(dic[(x[0], x[1], x[2])][0] + x[3]))
                dic[(x[0], x[1], x[2])][1] = sorted(list(set(dic[(x[0], x[1], x[2])][1] + x[4])))

        DFG = [(x[0], x[1], x[2], y[0], y[1]) for x, y in sorted(dic.items(), key=lambda t: t[0][1])]
        return sorted(DFG, key=lambda x: x[1]), states

    else:
        DFG = []
        for child in root_node.children:
            if child.type in do_first_statement:
                temp, states = DFG_python(child, index_to_code, states)
                DFG += temp
        for child in root_node.children:
            if child.type not in do_first_statement:
                temp, states = DFG_python(child, index_to_code, states)
                DFG += temp
        return sorted(DFG, key=lambda x: x[1]), states
```

### Number of "for multiple targets" refactorings made:
- 4 refactorings of "for multiple targets" idiom where I combined multiple assignments on the same line:

1. `assignment, if_statement, for_statement, while_statement = [...], [...], [...], [...]`
2. `do_first_statement, def_statement, states = [...], [...], states.copy()`
3. `left_nodes, right_nodes = [...]`
4. `left_nodes, right_nodes = [...] (in multiple places)`

By consolidating assignments that logically relate to the same sequence, the code becomes slightly more concise while maintaining readability.

