def get_indexes(self, cursor, table_name):
    cursor.execute(f"SHOW INDEX FROM {self.connection.ops.quote_name(table_name)}")

    # Fetch all rows
    rows = list(cursor.fetchall())

    # Pass 1: Identify multicolumn indexes
    multicol_indexes = {index_name for _, _, index_name, seq_in_index, *_ in rows if seq_in_index > 1}

    indexes = {}

    # Pass 2: Process the single-column indexes
    for _, non_unique, index_name, _, column_name, *_ in rows:
        if index_name in multicol_indexes:
            continue

        if column_name not in indexes:
            indexes[column_name] = {'primary_key': False, 'unique': False}

        if index_name == 'PRIMARY':
            indexes[column_name]['primary_key'] = True

        if not non_unique:
            indexes[column_name]['unique'] = True

    return indexes

