    for (fname, part1, part2), v in self.matched_items.items():
        for appear in {x[0] for x in v}:  # Converted to set comprehension directly
            # 32 is green, 31 is red
            if not self.no_fancy_color:
                fname_colored = colorize(fname, '36')
                appear = appear.replace(part1, colorize(part1, '33'))
                appear = appear.replace(part2, colorize(part2, '31'))
            else:
                fname_colored = fname  # fname remains un-altered if colors aren't applicable

            print(f'{fname_colored}: {appear}')

