def get_foreign_keys(self):
    """ Yields (parent_schema, parent_table, parent_column, child_schema, child_table,
        child_column) tuples."""
    query = mssqlqueries.get_foreignkeys()
    logger.info(u'Foreign keys query: %s', query)
    for tabular_result in self.execute_query(query):
        for parent_schema, parent_table, parent_column, child_schema, child_table, child_column in tabular_result[0]:
            yield ForeignKey(parent_schema, parent_table, parent_column, child_schema, child_table, child_column)

