def write_obj(self, verts, file_name):
    with open(file_name, 'w') as fp:
        # Unpack the vertex coordinates directly in the loop
        for x, y, z in verts:
            fp.write(f'v {x} {y} {z}\n')  # Used f-string for better readability

        # Unpack the face indices directly in the loop
        for v1, v2, v3 in (face + 1 for face in self.faces):
            fp.write(f'f {v1} {v2} {v3}\n')  # Used f-string for better readability

