```python
def selection_restore(bm=None, uv_layers=None, restore_seams=False):
    mode = bpy.context.object.mode
    if mode != 'EDIT':
        bpy.ops.object.mode_set(mode='EDIT')
    if bm is None:
        bm, uv_layers = bmesh.from_edit_mesh(bpy.context.active_object.data), bm.loops.layers.uv.verify()

    tool_settings = bpy.context.scene.tool_settings
    tool_settings.use_uv_select_sync = settings.use_uv_sync
    tool_settings.uv_select_mode = settings.selection_uv_mode

    contextViewUV = utilities_ui.GetContextViewUV()
    if contextViewUV:
        area_space = contextViewUV['area'].spaces[0]
        area_space.pivot_point = settings.selection_uv_pivot
        bpy.ops.uv.cursor_set(contextViewUV, location=settings.selection_uv_pivot_pos)

    # Restore seams
    if restore_seams:
        bpy.ops.mesh.select_all(action='SELECT')
        bpy.ops.mesh.mark_seam(clear=True)
        for edge in settings.seam_edges:
            edge.seam = True

    bpy.ops.mesh.select_all(action='DESELECT')

    # Selection Mode
    tool_settings.mesh_select_mode = settings.selection_mode

    # Vertex selection
    if settings.selection_mode[0]:
        bm.verts.ensure_lookup_table()
        for index in settings.selection_vert_indexies:
            if index < len(bm.verts):
                bm.verts[index].select = True

    # Edge selection
    if settings.selection_mode[1]:
        bm.edges.ensure_lookup_table()
        for index in settings.selection_edge_indexies:
            if index < len(bm.edges):
                bm.edges[index].select = True

    # Face selection
    bm.faces.ensure_lookup_table()
    for index in settings.selection_face_indexies:
        if index < len(bm.faces):
            bm.faces[index].select = True

    # UV Face-UV Selections (Loops)
    if contextViewUV:
        bpy.ops.uv.select_all(contextViewUV, action='DESELECT')
    else:
        for face in bm.faces:
            for loop in face.loops:
                loop[uv_layers].select = False

    for face_index, vert_index in settings.selection_uv_loops:
        for loop in bm.faces[face_index].loops:
            if loop.vert.index == vert_index:
                loop[uv_layers].select = True
                break

    bpy.context.view_layer.update()
    bpy.ops.object.mode_set(mode=mode)
```

