def update(self, vals):
        # type: (Any) -> None
        try:
            ordereddict.update(self, vals)
        except TypeError:
            # probably a dict that is used
            for x in vals:
                self[x] = vals[x]
        try:
            self._ok.update(vals.keys())  # type: ignore
        except AttributeError:
            # assume a list/tuple of two element lists/tuples
            for x in vals:
                self._ok.add(x[0])

gpt_code:
def update(self, vals):
    # type: (Any) -> None
    try:
        ordereddict.update(self, vals)
    except TypeError:
        # probably a dict that is used
        for key, value in vals.items():
            self[key] = value  # Unpacking the key-value pairs from the dict directly
    try:
        self._ok.update(vals.keys())  # type: ignore
    except AttributeError:
        # assume a list/tuple of two element lists/tuples
        for key, _ in vals:  # Unpacking the key from (key, _) in list/tuples
            self._ok.add(key)

