def write_log(log_file, entries):
  new_lines = []
  for ent in entries:
    new_lines.append('\t'.join((ent[1], ent[0])))
  open(log_file, 'w').write('\n'.join(new_lines) + '\n')

def save_track(results, out_root, video_to_images, video_names, data_split='val'):
    assert out_root is not None
    out_dir = os.path.join(out_root, data_split)
    if not os.path.exists(out_dir):
        os.mkdir(out_dir)

    # save it in standard mot format.
    track_dir = os.path.join(out_dir, "tracks")
    if not os.path.exists(track_dir):
        os.mkdir(track_dir)

    for video_id in video_to_images.keys():
        video_to_image_infos = video_to_images[video_id]
        video_name = video_names[video_id]
        file_path = os.path.join(track_dir, "{}.txt".format(video_name))
        f = open(file_path, "w")
        tracks = defaultdict(list)
        for image_info in video_to_image_infos:
            image_id, frame_id = image_info["image_id"], image_info["frame_id"]
            if image_id in results:
                result = results[image_id]
                for item in result:
                    if not ("tracking_id" in item):
                        raise NotImplementedError
                    tracking_id = item["tracking_id"]
                    bbox = item["bbox"]
                    bbox = [bbox[0], bbox[1], bbox[2], bbox[3], item['score'], item['active']]
                    tracks[tracking_id].append([frame_id] + bbox)

        rename_track_id = 0
        for track_id in sorted(tracks):
            rename_track_id += 1
            for t in tracks[track_id]:
                if t[6] > 0:
                    f.write("{},{},{:.2f},{:.2f},{:.2f},{:.2f},-1,-1,-1,-1\n".format(
                        t[0], rename_track_id, t[1], t[2], t[3] - t[1], t[4] - t[2]))
        f.close()

gpt_code:
import os
from collections import defaultdict

def save_track(results, out_root, video_to_images, video_names, data_split='val'):
    assert out_root is not None
    out_dir = os.path.join(out_root, data_split)
    if not os.path.exists(out_dir):
        os.mkdir(out_dir)

    # save it in standard mot format.
    track_dir = os.path.join(out_dir, "tracks")
    if not os.path.exists(track_dir):
        os.mkdir(track_dir)

    for video_id, video_to_image_infos in video_to_images.items():
        video_name = video_names[video_id]
        file_path = os.path.join(track_dir, f"{video_name}.txt")
        with open(file_path, "w") as f:
            tracks = defaultdict(list)
            for image_info in video_to_image_infos:
                image_id, frame_id = image_info["image_id"], image_info["frame_id"]
                if image_id in results:
                    for item in results[image_id]:
                        if "tracking_id" not in item:
                            raise NotImplementedError
                        tracking_id, bbox = item["tracking_id"], item["bbox"]
                        # Using multiple targets unpacking for bbox and two values in one go
                        x1, y1, x2, y2, score, active = bbox[0], bbox[1], bbox[2], bbox[3], item['score'], item['active']
                        tracks[tracking_id].append([frame_id, x1, y1, x2, y2, score, active])

            rename_track_id = 0
            for track_id in sorted(tracks):
                rename_track_id += 1
                for frame_id, x1, y1, x2, y2, score, active in tracks[track_id]:
                    if active > 0:
                        f.write(f"{frame_id},{rename_track_id},{x1:.2f},{y1:.2f},{x2 - x1:.2f},{y2 - y1:.2f},-1,-1,-1,-1\n")

